  );
};

export default EditorContainer;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import {
  useSplitStore,
  useEditorStore,
  useFileStore,
  Pane,
  PaneLeaf,
  PaneSplit,
  SplitDirection,
} from '../../stores';
import { VditorEditor } from './VditorEditor';
import { PaneWelcome } from './PaneWelcome';
import { ContextMenu } from './ContextMenu';
import { useFileOperations } from '../../hooks/useFileOperations';
import { isTauriCached } from '../../utils/platform';
import '../../styles/split.css';

interface PaneContainerProps {
  tabPath: string;
}

interface ContextMenuState {
  visible: boolean;
  x: number;
  y: number;
  paneId: string;
  hasDocument: boolean;
}

interface DragState {
  isOver: boolean;
  paneId: string;
}

export const PaneContainer: React.FC<PaneContainerProps> = ({ tabPath }) => {
  const splitState = useSplitStore((state) => state.getCurrentState(tabPath));
  const activePaneId = splitState?.activePaneId;
  const initTabSplitState = useSplitStore((state) => state.initTabSplitState);
  const splitPaneAction = useSplitStore((state) => state.splitPane);
  const closePane = useSplitStore((state) => state.closePane);
  const setPaneDocument = useSplitStore((state) => state.setPaneDocument);
  const setActivePane = useSplitStore((state) => state.setActivePane);
  const setSplitRatio = useSplitStore((state) => state.setSplitRatio);
  const getPaneCount = useSplitStore((state) => state.getPaneCount);
  const getDocumentsInPanes = useSplitStore((state) => state.getDocumentsInPanes);
  const ensureDocument = useEditorStore((state) => state.ensureDocument);
  const setActiveTab = useEditorStore((state) => state.setActiveTab);
  const getFileHandle = useFileStore((state) => state.getFileHandle);
  const { handleOpenFile: openFileFromOps } = useFileOperations();

  const [contextMenu, setContextMenu] = useState<ContextMenuState>({
    visible: false,
    x: 0,
    y: 0,
    paneId: '',
    hasDocument: false,
  });

  const [dragState, setDragState] = useState<DragState>({
    isOver: false,
    paneId: '',
  });

  const draggingRef = useRef<{
    splitPaneId: string;
    startX: number;
    startY: number;
    startRatio: number;
    direction: SplitDirection;
  } | null>(null);

  useEffect(() => {
    if (!splitState) {
      const doc = useEditorStore.getState().documents[tabPath];
      initTabSplitState(tabPath, doc ? tabPath : '');
    }
  }, [tabPath, splitState, initTabSplitState]);

  const handlePaneClick = useCallback(
    (paneId: string, docPath: string | null) => {
      setActiveTab(tabPath);
      if (splitState && paneId !== splitState.activePaneId) {
        setActivePane(tabPath, paneId);
      }
      if (docPath) {
        useEditorStore.setState({ activeDocPath: docPath });
      }
    },
    [tabPath, splitState, setActivePane, setActiveTab],
  );

  const handleContextMenu = useCallback(
    (e: React.MouseEvent, paneId: string, docPath: string | null) => {
      e.preventDefault();
      e.stopPropagation();
      setContextMenu({
        visible: true,
        x: e.clientX,
        y: e.clientY,
        paneId,
        hasDocument: docPath !== null,
      });
    },
    [],
  );

  const closeContextMenu = useCallback(() => {
    setContextMenu((prev) => ({ ...prev, visible: false }));
  }, []);

  const handleNewFile = useCallback(() => {
    const fileName = `鏂板缓鏂囨。-${Date.now()}.md`;
    const content = `# 鏂板缓鏂囨。\n\n鍦ㄨ繖閲屽紑濮嬪啓浣?..\n`;
    ensureDocument(fileName, content, true);

    const newDocPath = fileName;
    setTimeout(() => {
      setPaneDocument(tabPath, contextMenu.paneId, newDocPath);
      setActivePane(tabPath, contextMenu.paneId);
    }, 50);
  }, [tabPath, contextMenu.paneId, ensureDocument, setPaneDocument, setActivePane]);

  const handleOpenFileInPane = useCallback(
    (paneId: string) => {
      openFileFromOps((docPath: string) => {
        setTimeout(() => {
          setPaneDocument(tabPath, paneId, docPath);
          setActivePane(tabPath, paneId);
        }, 50);
      });
    },
    [tabPath, openFileFromOps, setPaneDocument, setActivePane],
  );

  const handleOpenFileFromContextMenu = useCallback(() => {
    openFileFromOps((docPath: string) => {
      setTimeout(() => {
        setPaneDocument(tabPath, contextMenu.paneId, docPath);
        setActivePane(tabPath, contextMenu.paneId);
      }, 50);
    });
  }, [tabPath, contextMenu.paneId, openFileFromOps, setPaneDocument, setActivePane]);

  const handleCloseDocument = useCallback(() => {
    setPaneDocument(tabPath, contextMenu.paneId, null);
  }, [tabPath, contextMenu.paneId, setPaneDocument]);

  const handleClosePane = useCallback(() => {
    const newActiveDocPath = closePane(tabPath, contextMenu.paneId);
    if (newActiveDocPath) {
      useEditorStore.setState({
        activeDocPath: newActiveDocPath,
        activeTabPath: tabPath,
      });
    }
  }, [tabPath, contextMenu.paneId, closePane]);

  const handleDragOver = useCallback((e: React.DragEvent, paneId: string) => {
    e.preventDefault();
    e.stopPropagation();
    e.dataTransfer.dropEffect = 'copy';
    setDragState({ isOver: true, paneId });
  }, []);

  const handleDragLeave = useCallback(() => {
    setDragState({ isOver: false, paneId: '' });
  }, []);

  const handleDrop = useCallback(
    async (e: React.DragEvent, paneId: string) => {
      e.preventDefault();
      e.stopPropagation();
      setDragState({ isOver: false, paneId: '' });

      let docPath: string | null = null;
      let content: string | null = null;

      const types = e.dataTransfer.types;
      if (types.includes('application/x-file-path')) {
        const internalDragData = e.dataTransfer.getData('application/x-file-path');
        if (internalDragData && internalDragData.startsWith('file://')) {
          docPath = internalDragData;
          const realPath = internalDragData.replace(/^file:\/\//, '');
          try {
            if (isTauriCached()) {
              const { readTextFile } = await import('@tauri-apps/plugin-fs');
              content = await readTextFile(realPath);
            } else {
              const handle = getFileHandle(realPath) || getFileHandle(realPath.replace(/\\/g, '/'));
              if (handle && handle.kind === 'file') {
                const file = await handle.getFile();
                content = await file.text();
              }
            }
          } catch (err) {
            console.error('浠庢枃浠舵爲鎷栨斁鎵撳紑鏂囦欢澶辫触:', err);
            return;
          }
        }
      }

      if (!docPath) {
        const files = Array.from(e.dataTransfer.files).filter(
          (f) => f.name.endsWith('.md') || f.name.endsWith('.markdown') || f.name.endsWith('.txt'),
        );
        if (files.length > 0) {
          const file = files[0];
          const filePath = (file as any).path;
          if (filePath) {
            docPath = `file://${filePath}`;
            content = await file.text();
          } else {
            docPath = `file://${file.name}`;
            content = await file.text();
          }
        }
      }

      if (!docPath || content === null) return;

      const existingDocs = getDocumentsInPanes(tabPath);
      if (existingDocs.includes(docPath)) return;

      ensureDocument(docPath, content, false);
      setPaneDocument(tabPath, paneId, docPath);
      setActivePane(tabPath, paneId);
    },
    [tabPath, ensureDocument, setPaneDocument, setActivePane, getFileHandle, getDocumentsInPanes],
  );

  const handleDividerMouseDown = useCallback(
    (e: React.MouseEvent, splitPaneId: string, direction: SplitDirection, currentRatio: number) => {
      e.preventDefault();
      const dividerElement = e.currentTarget;
      const container = dividerElement.parentElement;
      if (!container) return;

      draggingRef.current = {
        splitPaneId,
        startX: e.clientX,
        startY: e.clientY,
        startRatio: currentRatio,
        direction,
      };

      const handleMouseMove = (moveEvent: MouseEvent) => {
        if (!draggingRef.current) return;

        const { startX, startY, startRatio, direction, splitPaneId: id } = draggingRef.current;

        const rect = container.getBoundingClientRect();

        let newRatio: number;
        if (direction === 'vertical') {
          const deltaX = moveEvent.clientX - startX;
          const containerWidth = rect.width;
          const ratioDelta = deltaX / containerWidth;
          newRatio = startRatio + ratioDelta;
        } else {
          const deltaY = moveEvent.clientY - startY;
          const containerHeight = rect.height;
          const ratioDelta = deltaY / containerHeight;
          newRatio = startRatio + ratioDelta;
        }

        newRatio = Math.max(0.1, Math.min(0.9, newRatio));

        setSplitRatio(tabPath, id, newRatio);
      };

      const handleMouseUp = () => {
        if (draggingRef.current) {
          dividerElement.classList.remove('dragging');
        }
        draggingRef.current = null;
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);
      };

      dividerElement.classList.add('dragging');
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
    },
    [tabPath, setSplitRatio],
  );

  if (!splitState) {
    return null;
  }

  const paneCount = getPaneCount(tabPath);
  const canClosePane = paneCount > 1;

  const renderPane = (pane: Pane): React.ReactNode => {
    if (pane.type === 'leaf') {
      const isActive = pane.id === activePaneId;
      const isDragOver = dragState.isOver && dragState.paneId === pane.id;

      return (
        <div
          key={pane.id}
          className={`pane-leaf ${isActive && paneCount > 1 ? 'active' : ''} ${isDragOver ? 'drag-over' : ''}`}
          data-pane-id={pane.id}
          data-tab-path={tabPath}
          onClick={() => handlePaneClick(pane.id, pane.docPath)}
          onContextMenu={(e) => handleContextMenu(e, pane.id, pane.docPath)}
          onDragOver={(e) => handleDragOver(e, pane.id)}
          onDragLeave={handleDragLeave}
          onDrop={(e) => handleDrop(e, pane.id)}
        >
          {pane.docPath ? (
            <VditorEditor key={pane.docPath} path={pane.docPath} isInPane={paneCount > 1} />
          ) : (
            <PaneWelcome
              onNewFile={() => {
                const fileName = `鏂板缓鏂囨。-${Date.now()}.md`;
                const content = `# 鏂板缓鏂囨。\n\n鍦ㄨ繖閲屽紑濮嬪啓浣?..\n`;
                ensureDocument(fileName, content, true);
                setTimeout(() => {
                  setPaneDocument(tabPath, pane.id, fileName);
                  setActivePane(tabPath, pane.id);
                }, 50);
              }}
              onOpenFile={() => handleOpenFileInPane(pane.id)}
            />
          )}
        </div>
      );
    }

    const splitNode = pane as PaneSplit;
    const [firstChild, secondChild] = splitNode.children;
    const isActive = splitNode.id === activePaneId;
    const firstStyle =
      splitNode.direction === 'vertical'
        ? { flex: `0 0 calc(${splitNode.ratio * 100}% - 2px)` }
        : { flex: `0 0 calc(${splitNode.ratio * 100}% - 2px)` };
    const secondStyle =
      splitNode.direction === 'vertical'
        ? { flex: `0 0 calc(${(1 - splitNode.ratio) * 100}% - 2px)` }
        : { flex: `0 0 calc(${(1 - splitNode.ratio) * 100}% - 2px)` };

    return (
      <div
        key={splitNode.id}
        className={`pane-container ${splitNode.direction} flex-1 min-w-0 min-h-0`}
      >
        <div style={firstStyle} className="pane-leaf-wrapper">
          {renderPane(firstChild)}
        </div>
        <div
          className={`pane-divider ${splitNode.direction} ${isActive ? 'active' : ''}`}
          onMouseDown={(e) =>
            handleDividerMouseDown(e, splitNode.id, splitNode.direction, splitNode.ratio)
          }
        />
        <div style={secondStyle} className="pane-leaf-wrapper">
          {renderPane(secondChild)}
        </div>
      </div>
    );
  };

  return (
    <>
      <div className="pane-container vertical h-full w-full">{renderPane(splitState.paneTree)}</div>

      {contextMenu.visible && (
        <ContextMenu
          x={contextMenu.x}
          y={contextMenu.y}
          hasDocument={contextMenu.hasDocument}
          canClosePane={canClosePane}
          onNewFile={handleNewFile}
          onOpenFile={handleOpenFileFromContextMenu}
          onCloseDocument={handleCloseDocument}
          onClosePane={handleClosePane}
          onClose={closeContextMenu}
        />
      )}
    </>
  );
};

export default PaneContainer;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import Vditor from 'vditor';

// 鎵╁睍Window绫诲瀷锛屾坊鍔爁ind鏂规硶
declare global {
  interface Window {
    find(
      text: string,
      caseSensitive?: boolean,
      backward?: boolean,
      wrapAround?: boolean,
      wholeWord?: boolean,
      searchInFrames?: boolean,
      showDialog?: boolean,
    ): boolean;
  }
}

interface ReplaceDialogProps {
  isOpen: boolean;
  onClose: () => void;
  vditor: Vditor | null;
}

/**
 * 鏌ユ壘鏇挎崲寮圭獥缁勪欢
 *
 * 鍔熻兘锛歕n * - 鏌ユ壘锛氫娇鐢ㄦ祻瑙堝櫒鍘熺敓window.find()鏌ユ壘骞堕珮浜枃鏈琝n * - 鏇挎崲锛氭浛鎹㈠綋鍓嶉€変腑鐨勬枃鏈琝n * - 鍏ㄩ儴鏇挎崲锛氭浛鎹㈡墍鏈夊尮閰嶉」
 *
 * 浣跨敤娴忚鍣ㄥ師鐢熸煡鎵惧姛鑳斤紝鏀寔楂樹寒鍜岄€変腑鏁堟灉
 */
export const ReplaceDialog: React.FC<ReplaceDialogProps> = ({ isOpen, onClose, vditor }) => {
  const [findText, setFindText] = useState('');
  const [replaceText, setReplaceText] = useState('');
  const [matchCount, setMatchCount] = useState(0);
  const [currentMatch, setCurrentMatch] = useState(0);
  const findInputRef = useRef<HTMLInputElement>(null);

  // 寮圭獥鎵撳紑鏃惰嚜鍔ㄨ仛鐒﹀埌鏌ユ壘杈撳叆妗哱n  useEffect(() => {
    if (isOpen && findInputRef.current) {
      findInputRef.current.focus();
      findInputRef.current.select();
      // 閲嶇疆鐘舵€乗n      setMatchCount(0);
    }
  }, [isOpen]);

  // 娓呴櫎鎵€鏈夐珮浜甛n  const clearHighlights = useCallback(() => {
    const editorElement =
      document.querySelector('.vditor-ir .vditor-reset') ||
      document.querySelector('.vditor-sv .vditor-reset') ||
      document.querySelector('.vditor-wysiwyg .vditor-reset') ||
      document.querySelector('.vditor-reset');

    if (!editorElement) return;

    const highlights = editorElement.querySelectorAll('.find-highlight');
    highlights.forEach((el) => {
      const parent = el.parentNode;
      if (parent) {
        parent.replaceChild(document.createTextNode(el.textContent || ''), el);
        parent.normalize();
      }
    });

    // 娓呴櫎閫夊尯
    const selection = window.getSelection();
    if (selection) {
      selection.removeAllRanges();
    }
  }, []);

  // ESC 閿叧闂脊绐梊n  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && isOpen) {
        e.preventDefault();
        e.stopPropagation();
        e.stopImmediatePropagation();
        // 娓呴櫎楂樹寒
        clearHighlights();
        onClose();
      }
    };
    window.addEventListener('keydown', handleKeyDown, true);
    return () => {
      window.removeEventListener('keydown', handleKeyDown, true);
    };
  }, [isOpen, onClose, clearHighlights]);

  // 杈呭姪鍑芥暟锛氳浆涔夋鍒欒〃杈惧紡鐗规畩瀛楃
  const escapeRegExp = (string: string): string => {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  };

  /**
   * 缁熻鍖归厤鏁伴噺
   */
  const countMatches = useCallback(() => {
    if (!findText || !vditor) return 0;

    const content = vditor.getValue();
    try {
      const regex = new RegExp(escapeRegExp(findText), 'gi');
      const matches = content.match(regex);
      return matches ? matches.length : 0;
    } catch (error) {
      console.error('鏌ユ壘澶辫触:', error);
      return 0;
    }
  }, [findText, vditor]);

  /**
   * 鏌ユ壘鍔熻兘 - DOM閬嶅巻+楂樹寒鏂规
   */
  const handleFind = useCallback(() => {
    if (!findText || !vditor) return;

    // 鑾峰彇缂栬緫鍣ㄥ厓绱燶n    const editorElement =
      document.querySelector('.vditor-ir .vditor-reset') ||
      document.querySelector('.vditor-sv .vditor-reset') ||
      document.querySelector('.vditor-wysiwyg .vditor-reset') ||
      document.querySelector('.vditor-reset');

    if (!editorElement) {
      alert('鏃犳硶鎵惧埌缂栬緫鍖哄煙');
      return;
    }

    // 娓呴櫎涔嬪墠鐨勯珮浜甛n    clearHighlights();

    // 鏌ユ壘骞堕珮浜墍鏈夊尮閰峔n    const matches: { node: Text; start: number; end: number }[] = [];
    const walker = document.createTreeWalker(editorElement, NodeFilter.SHOW_TEXT, null);
    const regex = new RegExp(escapeRegExp(findText), 'gi');

    let node;
    while ((node = walker.nextNode() as Text)) {
      const text = node.textContent || '';
      let match;
      while ((match = regex.exec(text))) {
        matches.push({
          node,
          start: match.index,
          end: match.index + findText.length,
        });
      }
    }

    setMatchCount(matches.length);
    setCurrentMatch(matches.length > 0 ? 1 : 0);

    if (matches.length === 0) {
      alert('鏈壘鍒板尮閰嶉」');
      return;
    }

    // 楂樹寒鎵€鏈夊尮閰嶏紙浠庡悗寰€鍓嶏紝閬垮厤绱㈠紩鍙樺寲锛塡n    for (let i = matches.length - 1; i >= 0; i--) {
      const match = matches[i];
      const range = document.createRange();
      range.setStart(match.node, match.start);
      range.setEnd(match.node, match.end);

      const span = document.createElement('span');
      span.className = 'find-highlight';
      span.style.backgroundColor = '#ffeb3b';
      span.style.color = '#000';
      span.style.borderRadius = '2px';
      span.dataset.matchIndex = String(i + 1);

      range.surroundContents(span);
    }

    // 婊氬姩鍒扮涓€涓尮閰峔n    const firstHighlight = editorElement.querySelector('.find-highlight') as HTMLElement;
    if (firstHighlight) {
      firstHighlight.scrollIntoView({ behavior: 'smooth', block: 'center' });
      firstHighlight.style.backgroundColor = '#ff9800'; // 褰撳墠鍖归厤鐢ㄤ笉鍚岄鑹瞈n    }
  }, [findText, vditor, clearHighlights]);

  /**
   * 鏌ユ壘涓嬩竴涓?- 婊氬姩鍒颁笅涓€涓珮浜甛n   */
  const handleFindNext = useCallback(() => {
    if (!findText || matchCount === 0) return;

    // 鑾峰彇缂栬緫鍣ㄥ厓绱燶n    const editorElement =
      document.querySelector('.vditor-ir .vditor-reset') ||
      document.querySelector('.vditor-sv .vditor-reset') ||
      document.querySelector('.vditor-wysiwyg .vditor-reset') ||
      document.querySelector('.vditor-reset');

    if (!editorElement) return;

    // 閲嶇疆鎵€鏈夐珮浜鑹瞈n    const highlights = editorElement.querySelectorAll('.find-highlight');
    highlights.forEach((el) => {
      (el as HTMLElement).style.backgroundColor = '#ffeb3b';
    });

    // 鏇存柊璁℃暟
    const nextIndex = currentMatch >= matchCount ? 1 : currentMatch + 1;
    setCurrentMatch(nextIndex);

    // 鎵惧埌骞舵粴鍔ㄥ埌涓嬩竴涓尮閰峔n    const nextHighlight = editorElement.querySelector(
      `.find-highlight[data-match-index="${nextIndex}"]`,
    ) as HTMLElement;
    if (nextHighlight) {
      nextHighlight.scrollIntoView({ behavior: 'smooth', block: 'center' });
      nextHighlight.style.backgroundColor = '#ff9800'; // 褰撳墠鍖归厤鐢ㄤ笉鍚岄鑹瞈n    }
  }, [findText, matchCount, currentMatch]);

  /**
   * 鏇挎崲鍔熻兘 - 鏇挎崲褰撳墠楂樹寒鐨勬枃鏈紝鐒跺悗鏌ユ壘涓嬩竴涓猏n   */
  const handleReplace = useCallback(() => {
    if (!findText || !vditor) return;

    // 鑾峰彇缂栬緫鍣ㄥ厓绱燶n    const editorElement =
      document.querySelector('.vditor-ir .vditor-reset') ||
      document.querySelector('.vditor-sv .vditor-reset') ||
      document.querySelector('.vditor-wysiwyg .vditor-reset') ||
      document.querySelector('.vditor-reset');

    if (!editorElement) return;

    // 鎵惧埌褰撳墠楂樹寒鐨勫尮閰嶏紙姗欒壊鑳屾櫙锛塡n    const currentHighlight =
      editorElement.querySelector('.find-highlight[style*="rgb(255, 152, 0)"]') ||
      editorElement.querySelector('.find-highlight[style*="#ff9800"]');

    if (currentHighlight) {
      // 鍒涘缓range閫変腑褰撳墠楂樹寒鐨勬枃鏈琝n      const range = document.createRange();
      range.selectNodeContents(currentHighlight);

      const selection = window.getSelection();
      if (selection) {
        selection.removeAllRanges();
        selection.addRange(range);

        // 浣跨敤execCommand鏇挎崲
        document.execCommand('insertText', false, replaceText);

        // 鏇存柊鍖归厤鏁伴噺
        const newCount = matchCount - 1;
        setMatchCount(newCount);

        if (newCount > 0) {
          // 閲嶆柊鏌ユ壘浠ユ洿鏂伴珮浜甛n          setTimeout(() => {
            handleFind();
          }, 50);
        } else {
          setCurrentMatch(0);
        }
      }
    } else {
      // 濡傛灉娌℃湁褰撳墠楂樹寒锛屽厛鏌ユ壘
      handleFind();
    }
  }, [findText, replaceText, vditor, matchCount, handleFind]);

  /**
   * 鍏ㄩ儴鏇挎崲
   */
  const handleReplaceAll = useCallback(() => {
    if (!findText || !vditor) return;

    const content = vditor.getValue();
    try {
      const regex = new RegExp(escapeRegExp(findText), 'gi');
      const matches = content.match(regex);
      const count = matches ? matches.length : 0;

      if (count > 0) {
        // 鎵ц鍏ㄩ儴鏇挎崲
        const newContent = content.replace(regex, replaceText);
        vditor.setValue(newContent);

        // 鎻愮ず鏇挎崲鏁伴噺
        alert(`宸叉浛鎹?${count} 澶刞);

        // 閲嶇疆鐘舵€乗n        setMatchCount(0);
      } else {
        alert('鏈壘鍒板尮閰嶉」');
      }
    } catch (error) {
      console.error('鍏ㄩ儴鏇挎崲澶辫触:', error);
    }
  }, [findText, replaceText, vditor]);

  // 杈撳叆妗嗗洖杞﹁Е鍙戞煡鎵句笅涓€涓猏n  const handleFindKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      e.stopPropagation();
      if (matchCount > 0) {
        handleFindNext();
      } else {
        handleFind();
      }
    }
  };

  // 闃绘浜嬩欢鍐掓场
  const stopPropagation = (e: React.KeyboardEvent | React.MouseEvent) => {
    e.stopPropagation();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-start justify-center pt-20">
      {/* 閬僵灞?*/}
      <div
        className="absolute inset-0"
        onClick={() => {
          clearHighlights();
          onClose();
        }}
      />

      {/* 寮圭獥鍐呭 */}
      <div
        className="relative bg-[var(--editor-bg)] border border-[var(--editor-border)] rounded-lg shadow-xl p-5 min-w-[360px] animate-in fade-in slide-in-from-top-4 duration-200"
        onClick={stopPropagation}
        onKeyDown={stopPropagation}
        onKeyUp={stopPropagation}
        onKeyPress={stopPropagation}
      >
        {/* 鏍囬鏍?*/}
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-base font-medium text-[var(--editor-text)]">鏌ユ壘鍜屾浛鎹?/h3>
          <button
            onClick={() => {
              clearHighlights();
              onClose();
            }}
            className="p-1 rounded hover:bg-[var(--editor-code-bg)] text-[var(--editor-text-secondary)] hover:text-[var(--editor-text)] transition-colors"
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              width="16"
              height="16"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <line x1="18" y1="6" x2="6" y2="18"></line>
              <line x1="6" y1="6" x2="18" y2="18"></line>
            </svg>
          </button>
        </div>

        {/* 鍐呭鍖哄煙 */}
        <div className="space-y-4">
          {/* 鏌ユ壘杈撳叆妗?*/}
          <div>
            <label className="block text-sm mb-1.5 text-[var(--editor-text)]">鏌ユ壘鍐呭锛?/label>
            <input
              ref={findInputRef}
              type="text"
              value={findText}
              onChange={(e) => {
                setFindText(e.target.value);
                setMatchCount(0);
              }}
              onKeyDown={handleFindKeyDown}
              className="w-full px-3 py-2 bg-[var(--editor-bg)] border border-[var(--editor-border)] rounded-md text-sm text-[var(--editor-text)] placeholder-[var(--editor-text-secondary)] focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 transition-all"
              placeholder="杈撳叆瑕佹煡鎵剧殑鍐呭"
            />
            {/* 鍖归厤鏁伴噺鎻愮ず */}
            {matchCount > 0 && (
              <div className="text-xs text-[var(--editor-text-secondary)] mt-1.5 px-1">
                鎵惧埌 <span className="font-medium text-blue-500">{matchCount}</span> 涓尮閰嶉」
              </div>
            )}
          </div>

          {/* 鏇挎崲杈撳叆妗?*/}
          <div>
            <label className="block text-sm mb-1.5 text-[var(--editor-text)]">鏇挎崲涓猴細</label>
            <input
              type="text"
              value={replaceText}
              onChange={(e) => setReplaceText(e.target.value)}
              onKeyDown={stopPropagation}
              className="w-full px-3 py-2 bg-[var(--editor-bg)] border border-[var(--editor-border)] rounded-md text-sm text-[var(--editor-text)] placeholder-[var(--editor-text-secondary)] focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 transition-all"
              placeholder="杈撳叆鏇挎崲鍐呭锛堝彲涓虹┖锛塡

flex gap-2 pt-2">
            {/* 鏌ユ壘涓嬩竴涓寜閽?*/}
            <button
              onClick={matchCount > 0 ? handleFindNext : handleFind}
              disabled={!findText}
              className="flex-1 px-3 py-2 bg-[var(--editor-code-bg)] text-[var(--editor-text)] border border-[var(--editor-border)] rounded-md text-sm font-medium hover:bg-[var(--editor-surface)] disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
