// 璁＄畻绾枃鏈瓧鏁帮紙鍘婚櫎 markdown 璇硶鏍囪锛塡nfunction countPlainText(md: string): number {
  if (!md) return 0;

  let text = md;

  // 绉婚櫎浠ｇ爜鍧梊n  text = text.replace(/```[\s\S]*?```/g, '');

  // 绉婚櫎琛屽唴浠ｇ爜
  text = text.replace(/`[^`]+`/g, '');

  // 绉婚櫎鍥剧墖 ![alt](url)
  text = text.replace(/!\[[^\]]*\]\([^)]+\)/g, '');

  // 绉婚櫎閾炬帴 [text](url) 鈫?text
  text = text.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1');

  // 绉婚櫎绮椾綋 **text** 鎴?__text__
  text = text.replace(/\*\*([^*]+)\*\*/g, '$1');
  text = text.replace(/__([^_]+)__/g, '$1');

  // 绉婚櫎鏂滀綋 *text* 鎴?_text_
  text = text.replace(/(?<!\*)\*([^*\n]+)\*(?!\*)/g, '$1');
  text = text.replace(/(?<!_)_([^_\n]+)_(?!_)/g, '$1');

  // 绉婚櫎鍒犻櫎绾?~~text~~
  text = text.replace(/~~([^~]+)~~/g, '$1');

  // 绉婚櫎楂樹寒 ==text==
  text = text.replace(/==([^=]+)==/g, '$1');

  // 绉婚櫎涓婃爣 ^text^
  text = text.replace(/\^([^^\n]+)\^/g, '$1');

  // 绉婚櫎涓嬫爣 ~text~ (鍗曚釜娉㈡氮绾匡紝鎺掗櫎鍒犻櫎绾?
  text = text.replace(/(?<!~)~([^~\n]+)~(?!~)/g, '$1');

  // 绉婚櫎鏍囬鏍囪
  text = text.replace(/^#{1,6}\s*/gm, '');

  // 绉婚櫎鍒楄〃鏍囪
  text = text.replace(/^[\t ]*[-*+]\s+/gm, '');
  text = text.replace(/^[\t ]*\d+\.\s+/gm, '');

  // 绉婚櫎寮曠敤鏍囪
  text = text.replace(/^>\s*/gm, '');

  // 绉婚櫎姘村钩绾縗n  text = text.replace(/^[-*_]{3,}$/gm, '');

  // 绉婚櫎 [toc]
  text = text.replace(/\[toc\]/gi, '');

  // 绉婚櫎 HTML 鏍囩
  text = text.replace(/<[^>]+>/g, '');

  // 绉婚櫎澶氫綑绌虹櫧瀛楃
  text = text.replace(/[\n\r]+/g, '');
  text = text.trim();

  return text.length;
}

// 鏂囦欢杞?base64
function fileToBase64(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

// 鍔犺浇鏈湴鍥剧墖锛岃繑鍥瀊lob URL
async function loadLocalImage(imageSrc: string, docPath: string): Promise<string | null> {
  // 瑙ｆ瀽鍥剧墖璺緞
  const cleanSrc = imageSrc.replace(/^\.\//, '');

  try {
    if (isTauriCached()) {
      // Tauri 鐜锛氳鍙栨枃浠惰浆涓?blob URL
      const { readFile } = await import('@tauri-apps/plugin-fs');

      // 浠庢枃妗ｈ矾寰勬彁鍙栫洰褰曡矾寰刓n      let docDir = '';
      if (docPath.startsWith('file://')) {
        const fullPath = docPath.replace('file://', '');
        const lastSlash = Math.max(fullPath.lastIndexOf('/'), fullPath.lastIndexOf('\\'));
        if (lastSlash > 0) {
          docDir = fullPath.substring(0, lastSlash);
        }
      }

      const normalizedSrc = cleanSrc.replace(/\//g, '\\');
      const imagePath = `${docDir}\\${normalizedSrc}`;
      const imageData = await readFile(imagePath);
      const blob = new Blob([imageData]);
      const blobUrl = URL.createObjectURL(blob);
      return blobUrl;
    } else {
      // 娴忚鍣ㄧ幆澧僜n      const { rootHandle, dirHandles } = useFileStore.getState();

      if (!rootHandle) return null;

      // 浠庢枃妗ｈ矾寰勬彁鍙栫洰褰曡矾寰刓n      let docDirHandle: FileSystemDirectoryHandle = rootHandle;

      if (docPath.startsWith('file://')) {
        const fullPath = docPath.replace('file://', '');
        const lastSlash = fullPath.lastIndexOf('/');
        if (lastSlash > 0) {
          const dirPath = fullPath.substring(0, lastSlash);
          const foundHandle = dirHandles.get(dirPath);
          if (foundHandle) {
            docDirHandle = foundHandle;
          }
        }
      }

      const parts = cleanSrc.split('/');

      // 閬嶅巻璺緞鎵惧埌鍥剧墖鏂囦欢
      let currentDir = docDirHandle;
      for (let i = 0; i < parts.length - 1; i++) {
        currentDir = await currentDir.getDirectoryHandle(parts[i]);
      }

      const fileName = parts[parts.length - 1];
      const fileHandle = await currentDir.getFileHandle(fileName);
      const file = await fileHandle.getFile();

      // 鍒涘缓blob URL
      const blobUrl = URL.createObjectURL(file);
      return blobUrl;
    }
  } catch (err) {
    return null;
  }
}

// 澶勭悊鍗曚釜鍥剧墖鍏冪礌
function handleLocalImage(img: HTMLImageElement, docPath: string) {
  const src = img.getAttribute('src');
  if (!src) return;

  // 鍙鐞嗙浉瀵硅矾寰勭殑鏈湴鍥剧墖
  if (src.startsWith('http') || src.startsWith('data:') || src.startsWith('blob:')) return;

  // 鏍囪涓烘鍦ㄥ鐞嗭紝閬垮厤閲嶅澶勭悊
  if (img.dataset.loading === 'true') return;
  img.dataset.loading = 'true';

  loadLocalImage(src, docPath).then((blobUrl) => {
    if (blobUrl) {
      img.src = blobUrl;
    }
    img.dataset.loading = 'false';
  });
}

