                  }
                  onMouseEnter={() => setHoveredPath(rootPath)}
                  onMouseLeave={() => setHoveredPath(null)}
                >
                  <span className="w-4 h-4 flex items-center justify-center mr-1 text-[var(--sidebar-text-muted)]">
                    {expandedDirs.has(rootPath) ? (
                      <ChevronDown size={14} />
