import { useEffect, useRef, useCallback } from 'react';
import { useEditorStore, useSettingsStore, useFileStore } from '../stores';
import { isTauriCached } from '../utils/platform';

const STORAGE_KEY_DOCS = 'md-editor-docs';
const STORAGE_KEY_TABS = 'md-editor-tabs';
const STORAGE_KEY_ACTIVE_PATH = 'md-editor-active-path';

/**
 * 淇濆瓨鏂囦欢鍒版湰鍦帮紙浣跨敤娴忚鍣ㄤ笅杞斤級
 */
export function saveFileToLocal(fileName: string, content: string): void {
  const blob = new Blob([content], { type: 'text/markdown;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = fileName;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

/**
 * 浠庤矾寰勬彁鍙栨枃浠跺悕
 */
export function getFileName(path: string): string {
  let cleanPath = path;
  if (cleanPath.startsWith('file://')) {
    cleanPath = cleanPath.replace('file://', '');
  }
  const parts = cleanPath.replace(/\\/g, '/').split('/');
  return parts[parts.length - 1] || 'untitled.md';
}

/**
 * 鍐欏叆鏂囦欢鍒版枃浠剁郴缁焅n */
async function writeToFileSystem(docPath: string, content: string): Promise<boolean> {
  // 浠巇ocPath涓彁鍙栧畬鏁磋矾寰勶紙鍘绘帀file://鍓嶇紑锛塡n  const fullPath = docPath.startsWith('file://') ? docPath.replace('file://', '') : docPath;

  try {
    if (isTauriCached()) {
      const { writeTextFile } = await import('@tauri-apps/plugin-fs');
      await writeTextFile(fullPath, content);
      return true;
    } else {
      const fileHandles = useFileStore.getState().fileHandles;
      const handle = fileHandles.get(fullPath);

      if (!handle) {
        return false;
      }

      const writable = await handle.createWritable();
      await writable.write(content);
      await writable.close();
      return true;
    }
  } catch (err) {
    console.error('[FileSystem] 鍐欏叆鏂囦欢澶辫触:', err);
    return false;
  }
}

/**
 * 淇濆瓨鎵€鏈夋暟鎹埌 localStorage
 */
function saveToStorage(
  activeDocPath: string | null,
  tabs: string[],
  documents: Record<string, { content: string; isModified: boolean }>,
): void {
  try {
    const savedDocs: Record<string, { content: string; timestamp: number }> = {};
    for (const [path, doc] of Object.entries(documents)) {
      savedDocs[path] = {
        content: doc.content,
        timestamp: Date.now(),
      };
    }
    localStorage.setItem(STORAGE_KEY_DOCS, JSON.stringify(savedDocs));

    localStorage.setItem(STORAGE_KEY_TABS, JSON.stringify(tabs));

    if (activeDocPath) {
      localStorage.setItem(STORAGE_KEY_ACTIVE_PATH, activeDocPath);
    }
  } catch (error) {
    console.error('[AutoSave] 淇濆瓨鍒?localStorage 澶辫触:', error);
  }
}

/**
 * 鑷姩淇濆瓨 Hook
 */
export function useAutoSave(): void {
  const saveStatus = useEditorStore((state) => state.saveStatus);
  const activeDocPath = useEditorStore((state) => state.activeDocPath);
  const saveDocument = useEditorStore((state) => state.saveDocument);

  const autoSaveEnabled = useSettingsStore((state) => state.autoSave);
  const autoSaveDelay = useSettingsStore((state) => state.autoSaveDelay);

  const timeoutRef = useRef<number | null>(null);

  const performSave = useCallback(async () => {
    if (!activeDocPath) return;

    // 浣跨敤 getState() 閬垮厤璁㈤槄
    const { documents, tabs } = useEditorStore.getState();
    const doc = documents[activeDocPath];
    if (!doc) return;

    try {
      // 濡傛灉鏄痜ile://寮€澶寸殑鏂囨。锛屽皾璇曞啓鍏ユ枃浠剁郴缁焅n      if (activeDocPath.startsWith('file://')) {
        const written = await writeToFileSystem(activeDocPath, doc.content);

        if (written) {
          const savedDocs = JSON.parse(localStorage.getItem(STORAGE_KEY_DOCS) || '{}');
          delete savedDocs[activeDocPath];
          localStorage.setItem(STORAGE_KEY_DOCS, JSON.stringify(savedDocs));
        } else {
          saveToStorage(activeDocPath, tabs, documents);
        }
      } else {
        saveToStorage(activeDocPath, tabs, documents);
      }

      saveDocument(activeDocPath);
    } catch (error) {
      console.error('[AutoSave] 淇濆瓨澶辫触:', error);
    }
  }, [activeDocPath, saveDocument]);

  const scheduleSave = useCallback(() => {
    if (timeoutRef.current !== null) {
      window.clearTimeout(timeoutRef.current);
    }

    timeoutRef.current = window.setTimeout(() => {
      performSave();
      timeoutRef.current = null;
    }, autoSaveDelay);
  }, [performSave, autoSaveDelay]);

  useEffect(() => {
    if (!autoSaveEnabled) return;
    if (saveStatus !== 'unsaved') return;

    scheduleSave();

    return () => {
      if (timeoutRef.current !== null) {
        window.clearTimeout(timeoutRef.current);
        timeoutRef.current = null;
      }
    };
  }, [autoSaveEnabled, saveStatus, scheduleSave, autoSaveDelay]);

  useEffect(() => {
    return () => {
      if (timeoutRef.current !== null) {
        window.clearTimeout(timeoutRef.current);
        performSave();
      }
    };
  }, [performSave]);

  useEffect(() => {
    const handleBeforeUnload = () => {
      const { documents, tabs } = useEditorStore.getState();
      if (activeDocPath && documents[activeDocPath]?.isModified) {
        saveToStorage(activeDocPath, tabs, documents);
      }
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [activeDocPath]);
}

/**
 * 鍙﹀瓨涓哄姛鑳?Hook
 */
export function useSaveAsFile() {
  return useCallback(async () => {
    const { activeDocPath, documents, updateFilePath, saveDocument } = useEditorStore.getState();
    if (!activeDocPath) return;
    const doc = documents[activeDocPath];
    if (!doc) return;

    const defaultName =
      doc.content
        .split('\n')[0]
        .replace(/^#+\s*/, '')
        .trim() || '鏈懡鍚?;
    const fileName = `${defaultName}.md`;

    if (isTauriCached()) {
      try {
        const { save } = await import('@tauri-apps/plugin-dialog');
        const filePath = await save({
          defaultPath: fileName,
          filters: [{ name: 'Markdown', extensions: ['md'] }],
        });

        if (filePath) {
          const { writeTextFile } = await import('@tauri-apps/plugin-fs');
          await writeTextFile(filePath, doc.content);
          updateFilePath(activeDocPath, filePath);
          saveDocument(activeDocPath);
        }
      } catch (e) {
        console.error('Save as failed:', e);
      }
    } else {
      try {
        if ('showSaveFilePicker' in window) {
          const handle = await (window as any).showSaveFilePicker({
            suggestedName: fileName,
            types: [{ description: 'Markdown Files', accept: { 'text/markdown': ['.md'] } }],
          });

          const writable = await handle.createWritable();
          await writable.write(doc.content);
          await writable.close();

          updateFilePath(activeDocPath, handle.name);
          saveDocument(activeDocPath);
        } else {
          saveFileToLocal(fileName, doc.content);
          saveDocument(activeDocPath);
        }
      } catch (e) {
        console.error('Save as failed:', e);
      }
    }
  }, []);
}

/**
 * 鎵嬪姩淇濆瓨鍒版枃浠朵笅杞絓n */
export function useSaveToFile() {
  const saveAsFile = useSaveAsFile();

  return useCallback(async () => {
    const { activeDocPath, documents } = useEditorStore.getState();
    if (!activeDocPath) return;
    const doc = documents[activeDocPath];
    if (!doc) return;

    // 鏅鸿兘鍒ゆ柇锛氭柊寤烘枃妗ｆ垨娌℃湁filePath鏃讹紝鎵ц鍙﹀瓨涓篭n    if (doc.isNewFile || !doc.filePath) {
      await saveAsFile();
      return;
    }

    // 宸蹭繚瀛樻枃妗ｏ紝淇濆瓨鍒板師璺緞
    const written = await writeToFileSystem(doc.filePath, doc.content);
    if (written) {
      const { saveDocument } = useEditorStore.getState();
      saveDocument(activeDocPath);
      return;
    }

    // 鏃犳硶鍐欏叆鏂囦欢绯荤粺锛屼笅杞芥枃浠禱n    const fileName = getFileName(activeDocPath);
    saveFileToLocal(fileName, doc.content);
    const { saveDocument } = useEditorStore.getState();
    saveDocument(activeDocPath);
  }, [saveAsFile]);
}

import { useEffect, useCallback } from 'react';
import { useEditorStore, useFileStore } from '../stores';
import { isTauriCached } from '../utils/platform';
import { getCurrentWindow } from '@tauri-apps/api/window';

/**
 * 鏂囦欢鍙樺寲妫€娴?Hook
 * 褰撶獥鍙ｈ幏寰楃劍鐐规椂锛屾鏌ュ綋鍓嶆墦寮€鐨勬枃浠舵槸鍚︽湁澶栭儴淇敼
 */
export function useFileChangeDetection(): void {
  const activeDocPath = useEditorStore((state) => state.activeDocPath);
  const documents = useEditorStore((state) => state.documents);
  const openDocument = useEditorStore((state) => state.openDocument);

  // 璇诲彇鏂囦欢鍐呭
  const readFileContent = useCallback(async (filePath: string): Promise<string | null> => {
    try {
      if (isTauriCached()) {
        // Tauri 鐜
        const { readTextFile } = await import('@tauri-apps/plugin-fs');
        const content = await readTextFile(filePath);
        return content;
      } else {
        // 娴忚鍣ㄧ幆澧僜n        const { fileHandles, dirHandles, rootHandle } = useFileStore.getState();

        // 灏濊瘯澶氱璺緞鏍煎紡鏌ユ壘鏂囦欢鍙ユ焺
        let handle = fileHandles.get(filePath);

        if (!handle) {
          // 灏濊瘯鎻愬彇鏂囦欢鍚嶆煡鎵綷n          const fileName = filePath.split(/[/\\]/).pop();
          if (fileName) {
            handle = fileHandles.get(fileName);
          }
        }

        if (!handle) {
          // 灏濊瘯浣跨敤鐩稿璺緞锛堝幓鎺夋牴璺緞锛塡n          const parts = filePath.split(/[/\\]/);
          if (parts.length > 1) {
            const relativePath = parts.slice(1).join('/');
            handle = fileHandles.get(relativePath);
          }
        }

        if (handle) {
          const file = await handle.getFile();
          const content = await file.text();
          return content;
        }

        // 濡傛灉杩樻槸娌℃湁鎵惧埌锛屽皾璇曚粠鐩綍鍙ユ焺涓鍙朶n        const lastSlash = Math.max(filePath.lastIndexOf('/'), filePath.lastIndexOf('\\'));
        if (lastSlash > 0) {
          const dirPath = filePath.substring(0, lastSlash);
          const fileName = filePath.substring(lastSlash + 1);

          let dirHandle = dirHandles.get(dirPath);

          // 濡傛灉娌℃湁鎵惧埌鐩綍鍙ユ焺锛屽皾璇曚娇鐢ㄧ浉瀵硅矾寰刓n          if (!dirHandle) {
            const dirParts = dirPath.split(/[/\\]/);
            if (dirParts.length > 1) {
              const relativeDirPath = dirParts.slice(1).join('/');
              dirHandle = dirHandles.get(relativeDirPath);
            }
          }

          if (!dirHandle && dirPath === filePath.split(/[/\\]/)[0]) {
            // 濡傛灉鏄牴鐩綍锛屼娇鐢?rootHandle
            dirHandle = rootHandle || undefined;
          }

          if (dirHandle) {
            try {
              const fileHandle = await dirHandle.getFileHandle(fileName);
              const file = await fileHandle.getFile();
              const content = await file.text();
              return content;
            } catch (e) {
              // 浠庣洰褰曞彞鏌勮鍙栨枃浠跺け璐n            }
          }
        }

        return null;
      }
    } catch (err) {
      console.error('[FileChangeDetection] 璇诲彇鏂囦欢澶辫触:', err);
      return null;
    }
  }, []);

  // 妫€鏌ユ枃浠舵槸鍚︽湁鍙樺寲
  const checkFileChanges = useCallback(async () => {
    if (!activeDocPath) return;

    // 鍙鏌ユ枃浠讹紙file://寮€澶寸殑璺緞锛塡n    if (!activeDocPath.startsWith('file://')) return;

    const doc = documents[activeDocPath];
    if (!doc || doc.isModified) {
      // 濡傛灉鏂囨。鏈夋湭淇濆瓨鐨勪慨鏀癸紝涓嶆鏌ュ彉鍖朶n      return;
    }

    const filePath = activeDocPath.replace('file://', '');
    const fileContent = await readFileContent(filePath);

    if (fileContent === null) return;

    // 姣旇緝鍐呭
    if (fileContent !== doc.content) {
      // 鎻愮ず鐢ㄦ埛
      const shouldReload = confirm(
        `鏂囦欢 "${filePath.split(/[/\\]/).pop()}" 宸插湪澶栭儴琚慨鏀广€俓
\n鏄惁閲嶆柊鍔犺浇锛焅
锛堟湭淇濆瓨鐨勬洿鏀瑰皢涓㈠け锛塦,
      );

      if (shouldReload) {
        // 閲嶆柊鍔犺浇鏂囦欢
        openDocument(activeDocPath, fileContent, false);
      }
    }
  }, [activeDocPath, documents, readFileContent, openDocument]);

  // 鐩戝惉绐楀彛鐒︾偣鍙樺寲
  useEffect(() => {
    if (isTauriCached()) {
      // Tauri 鐜
      const unlisten = getCurrentWindow().onFocusChanged(({ payload: focused }) => {
        if (focused) {
          checkFileChanges();
        }
      });
      return () => {
        unlisten.then((fn) => fn());
      };
    } else {
      // 娴忚鍣ㄧ幆澧僜n      const handleFocus = () => {
        checkFileChanges();
      };
      window.addEventListener('focus', handleFocus);
      return () => window.removeEventListener('focus', handleFocus);
    }
  }, [checkFileChanges]);
}

import { useCallback } from 'react';
import { useFileStore, useEditorStore, TreeNode } from '../stores';
import { isTauriCached } from '../utils/platform';

export const useFileOperations = () => {
  const {
    fileTree,
    rootPath,
    setRootPath,
    setFileTree,
    setFileHandle,
    setDirHandle,
    setRootHandle,
    dirHandles,
    rootHandle,
    clearAll,
  } = useFileStore();
  const { openDocument, ensureDocument } = useEditorStore();

  const handleNewFile = useCallback(() => {
    const fileName = `鏂板缓鏂囨。-${Date.now()}.md`;
    const content = `# 鏂板缓鏂囨。\n\n鍦ㄨ繖閲屽紑濮嬪啓浣?..\n`;
    openDocument(fileName, content, true);
  }, [openDocument]);

  const handleOpenFile = useCallback(
    async (onFileOpened?: (docPath: string) => void) => {
      const isInPane = !!onFileOpened;
      const docOpener = isInPane ? ensureDocument : openDocument;

      if (isTauriCached()) {
        const { open } = await import('@tauri-apps/plugin-dialog');
        const { readTextFile } = await import('@tauri-apps/plugin-fs');

        const selected = await open({
          multiple: true,
          filters: [{ name: 'Markdown', extensions: ['md', 'markdown', 'txt'] }],
        });

        if (selected) {
          const files = Array.isArray(selected) ? selected : [selected];
          let lastOpenedPath: string | null = null;
          for (const filePath of files) {
            try {
              const content = await readTextFile(filePath as string);
              const docPath = `file://${filePath}`;
              docOpener(docPath, content, false);
              lastOpenedPath = docPath;
            } catch (err) {
              console.error('璇诲彇鏂囦欢澶辫触:', err);
            }
          }
          if (lastOpenedPath && onFileOpened) {
            onFileOpened(lastOpenedPath);
          }
        }
      } else {
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = '.md,.markdown,.txt';
        input.multiple = true;

        input.onchange = async (e) => {
          const files = (e.target as HTMLInputElement).files;
          if (!files) return;

          let lastOpenedPath: string | null = null;
          for (const file of files) {
            const content = await file.text();
            const docPath = `file://${file.name}`;
            docOpener(docPath, content, false);
            lastOpenedPath = docPath;
          }
          if (lastOpenedPath && onFileOpened) {
            onFileOpened(lastOpenedPath);
          }
        };

        input.click();
      }
    },
    [openDocument, ensureDocument],
  );

  // 璇诲彇鐩綍锛堟祻瑙堝櫒鐜锛屽彧璇诲彇涓€绾э紝涓嶉€掑綊锛塡n  const readDirectoryRecursive = useCallback(
    async (dirHandle: FileSystemDirectoryHandle, basePath: string): Promise<TreeNode[]> => {
      const nodes: TreeNode[] = [];

      setDirHandle(basePath, dirHandle);

      for await (const entry of (dirHandle as any).values()) {
        const nodePath = `${basePath}/${entry.name}`;

        if (
          entry.kind === 'file' &&
          (entry.name.endsWith('.md') || entry.name.endsWith('.markdown'))
        ) {
          nodes.push({
            name: entry.name,
            path: nodePath,
            isDir: false,
            handle: entry,
          });
        } else if (entry.kind === 'directory') {
          // 淇濆瓨瀛愮洰褰曠殑 handle锛岀敤浜庡欢杩熷姞杞絓n          setDirHandle(nodePath, entry as FileSystemDirectoryHandle);
          // 涓嶉€掑綊璇诲彇瀛愮洰褰曪紝寤惰繜鍔犺浇
          nodes.push({
            name: entry.name,
            path: nodePath,
            isDir: true,
            handle: entry,
            children: [], // 绌烘暟缁勶紝琛ㄧず鏈姞杞絓n          });
        }
      }

      nodes.sort((a, b) => {
        if (a.isDir && !b.isDir) return -1;
        if (!a.isDir && b.isDir) return 1;
        return a.name.localeCompare(b.name);
      });

      return nodes;
    },
    [setDirHandle],
  );

  // 浠?Tauri 璇诲彇鐩綍锛堝彧璇诲彇涓€绾э紝涓嶉€掑綊锛塡n  const readDirectoryTauri = useCallback(
    async (dirPath: string): Promise<TreeNode[]> => {
      const { readDir } = await import('@tauri-apps/plugin-fs');
      const nodes: TreeNode[] = [];

      setDirHandle(dirPath, dirPath as any);

      try {
        const entries = await readDir(dirPath);

        for (const entry of entries) {
          const nodePath =
            dirPath.endsWith('\\') || dirPath.endsWith('/')
              ? `${dirPath}${entry.name}`
              : `${dirPath}\\${entry.name}`;

          if (entry.isFile && (entry.name.endsWith('.md') || entry.name.endsWith('.markdown'))) {
            nodes.push({
              name: entry.name,
              path: nodePath,
              isDir: false,
              handle: undefined,
            });
          } else if (entry.isDirectory) {
            // 涓嶉€掑綊璇诲彇瀛愮洰褰曪紝寤惰繜鍔犺浇
            nodes.push({
              name: entry.name,
              path: nodePath,
              isDir: true,
              handle: undefined,
              children: [], // 绌烘暟缁勶紝琛ㄧず鏈姞杞絓n            });
          }
        }
      } catch (err) {
        console.error('璇诲彇鐩綍澶辫触:', err);
      }

      nodes.sort((a, b) => {
        if (a.isDir && !b.isDir) return -1;
        if (!a.isDir && b.isDir) return 1;
        return a.name.localeCompare(b.name);
      });

      return nodes;
    },
    [setDirHandle],
  );

  // 鎵撳紑鏂囦欢澶筡n  const handleOpenFolder = useCallback(async () => {
    if (isTauriCached()) {
      // Tauri 鐜锛氫娇鐢ㄥ師鐢熷璇濇
      const { open } = await import('@tauri-apps/plugin-dialog');

      const selected = await open({
        directory: true,
      });

      if (selected) {
        const folderPath = selected as string;
        const folderName = folderPath.split(/[/\\]/).pop() || folderPath;

        // 娓呯悊鏃х姸鎬乗n        clearAll();

        // 璁剧疆鏂扮姸鎬乗n        setRootPath(folderName);
        setRootHandle(folderPath as any);

        const tree = await readDirectoryTauri(folderPath);
        setFileTree(tree);
      }
    } else {
      // 娴忚鍣ㄧ幆澧冿細浣跨敤 File System Access API
      if ('showDirectoryPicker' in window) {
        try {
          const dirHandle = await (window as any).showDirectoryPicker();
          setRootPath(dirHandle.name);
          setRootHandle(dirHandle);

          const tree = await readDirectoryRecursive(dirHandle, dirHandle.name);
          setFileTree(tree);
        } catch (err) {
          // 鐢ㄦ埛鍙栨秷浜嗛€夋嫨
        }
      } else {
        alert('鎮ㄧ殑娴忚鍣ㄤ笉鏀寔鏂囦欢澶规祻瑙堬紝璇蜂娇鐢╘

鍔熻兘');
      }
    }
  }, [
    setRootPath,
    setFileTree,
    setRootHandle,
    readDirectoryRecursive,
    readDirectoryTauri,
    clearAll,
  ]);

  return {
    handleNewFile,
    handleOpenFile,
    handleOpenFolder,
    readDirectoryRecursive,
    readDirectoryTauri,
    fileTree,
    rootPath,
    rootHandle,
    dirHandles,
    setFileTree,
    setFileHandle,
    setDirHandle,
    setRootHandle,
    setRootPath,
    clearAll,
  };
};

