}

export function createEmbedWarning(message: string, mdPath?: string): string {
  const displayName = mdPath ? getFileDisplayName(mdPath) : '';
  return `<div class="embed-container embed-container--warning">
    <div class="embed-warning">
      <span class="embed-warning-icon">鈿狅笍</span>
      <span class="embed-warning-message">${message}</span>
      ${mdPath ? `<a class="embed-link" href="${mdPath}" title="鎵撳紑鏂囨。">鎵撳紑鏂囨。</a>` : ''}
    </div>
  </div>`;
}

export async function renderEmbedContent(mdPath: string, context: EmbedContext): Promise<string> {
  const { renderStack, currentDepth, embedCount, settings } = context;

  if (checkCircularReference(mdPath, renderStack)) {
    return createEmbedWarning(`妫€娴嬪埌寰幆寮曠敤: ${getFileDisplayName(mdPath)}`, mdPath);
  }

  if (currentDepth >= settings.maxDepth) {
    return createEmbedWarning(`宓屽娣卞害瓒呰繃闄愬埗 (鏈€澶?{settings.maxDepth}灞?`, mdPath);
  }

  if (embedCount >= settings.maxCount) {
    return createEmbedWarning(`宓屽叆鏂囨。鏁伴噺瓒呰繃闄愬埗 (鏈€澶?{settings.maxCount}涓?`);
  }

  const result = await readMdFileContent(mdPath);

  if (result.error || !result.content) {
    return createEmbedWarning(result.error || '鏂囦欢涓嶅瓨鍦?, mdPath);
  }

  return result.content;
}

export async function processEmbedsInMarkdown(
  content: string,
  context: EmbedContext,
): Promise<string> {
  // 鏂拌娉曪細[[xxx]](doc.md) 鎴?[[](doc.md)
  const embedRegex = /\[\[([^\]]*?)\]\]\(([^)]+)\)/gi;
  let processedContent = content;
  let currentEmbedCount = context.embedCount;

  const matches = [...content.matchAll(embedRegex)];

  for (const match of matches) {
    if (currentEmbedCount >= context.settings.maxCount) {
      processedContent = processedContent.replace(
        match[0],
        createEmbedWarning(`宓屽叆鏂囨。鏁伴噺瓒呰繃闄愬埗 (鏈€澶?{context.settings.maxCount}涓?`),
      );
      continue;
    }

    const displayText = match[1]?.trim() || '';
    const linkPath = match[2];

    if (!isLocalMdFile(linkPath)) {
      continue;
    }

    const resolvedPath = resolveDocPath(linkPath, context.rootDocPath);

    if (checkCircularReference(resolvedPath, context.renderStack)) {
      processedContent = processedContent.replace(
        match[0],
        createEmbedWarning(`妫€娴嬪埌寰幆寮曠敤`, resolvedPath),
      );
      continue;
    }

    if (context.currentDepth >= context.settings.maxDepth) {
      processedContent = processedContent.replace(
        match[0],
        createEmbedWarning(`宓屽娣卞害瓒呰繃闄愬埗`, resolvedPath),
      );
      continue;
    }

    const embedContent = await renderEmbedContent(resolvedPath, {
      ...context,
      renderStack: [...context.renderStack, resolvedPath],
      currentDepth: context.currentDepth + 1,
      embedCount: currentEmbedCount + 1,
    });

    if (embedContent && !embedContent.includes('embed-container--warning')) {
      const nestedContent = await processEmbedsInMarkdown(embedContent, {
        ...context,
        renderStack: [...context.renderStack, resolvedPath],
        currentDepth: context.currentDepth + 1,
        embedCount: currentEmbedCount + 1,
        rootDocPath: resolvedPath,
      });

      processedContent = processedContent.replace(
        match[0],
        createEmbedContainer(resolvedPath, nestedContent, displayText),
      );
    } else {
      processedContent = processedContent.replace(match[0], embedContent);
    }

    currentEmbedCount++;
  }

  return processedContent;
}

export function setupEmbedLazyLoading(container: HTMLElement): void {
  const embedContainers = container.querySelectorAll(
    '.embed-container:not(.embed-container--loading)',
  );

  if ('IntersectionObserver' in window) {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            const embedEl = entry.target as HTMLElement;
            embedEl.classList.add('embed-visible');
            observer.unobserve(embedEl);
          }
        });
      },
      {
        rootMargin: '100px',
        threshold: 0.1,
      },
    );

    embedContainers.forEach((el) => observer.observe(el));
  } else {
    embedContainers.forEach((el) => el.classList.add('embed-visible'));
  }
}

/**
 * 骞冲彴妫€娴嬪拰鏂囦欢鎿嶄綔宸ュ叿
 * 缁熶竴澶勭悊娴忚鍣ㄥ拰 Tauri 鐜鐨勫樊寮俓n */

// 浣跨敤 Tauri 瀹樻柟 API 妫€娴嬬幆澧冿紙寮傛锛塡nexport const isTauri = async (): Promise<boolean> => {
  try {
    const { isTauri: checkTauri } = await import('@tauri-apps/api/core');
    return checkTauri();
  } catch {
    return false;
  }
};

// 鍚屾妫€娴嬶紙鐢ㄤ簬鍒濆鍖栭樁娈碉級
// Tauri 2.0 withGlobalTauri 妯″紡涓嬶紝window.__TAURI__ 瀛樺湪
let _isTauriCache: boolean | null = null;
let _isTauriAsyncCache: boolean | null = null;

export const isTauriCached = (): boolean => {
  if (_isTauriCache === null) {
    _isTauriCache =
      typeof window !== 'undefined' &&
      ('__TAURI__' in window ||
        '__TAURI_INTERNALS__' in window ||
        navigator.userAgent.includes('Tauri'));
  }
  return _isTauriCache;
};

export const waitForTauri = async (): Promise<boolean> => {
  if (_isTauriAsyncCache !== null) {
    return _isTauriAsyncCache;
  }

  try {
    const { isTauri: checkTauri } = await import('@tauri-apps/api/core');
    const result = await checkTauri();
    _isTauriAsyncCache = result;
    _isTauriCache = result;
    return result;
  } catch (e) {
    _isTauriAsyncCache = false;
    return false;
  }
};

// 閲嶇疆缂撳瓨锛堢敤浜庢祴璇曪級
export const resetTauriCache = () => {
  _isTauriCache = null;
  _isTauriAsyncCache = null;
};

// 妫€娴嬫槸鍚﹀湪娴忚鍣ㄧ幆澧冧笖鏀寔 File System Access API
export const isFileSystemAccessSupported = (): boolean => {
  return typeof window !== 'undefined' && 'showDirectoryPicker' in window;
};

/**
 * 鏂囦欢鎿嶄綔灏佽
 */
export const fileOps = {
  // 璇诲彇鏂囨湰鏂囦欢
  async readTextFile(path: string): Promise<string> {
    if (isTauriCached()) {
      const { readTextFile } = await import('@tauri-apps/plugin-fs');
      return await readTextFile(path);
    } else {
      // 娴忚鍣ㄧ幆澧冮渶瑕佷紶鍏?handle
      throw new Error('Browser environment requires file handle');
    }
  },

  // 鍐欏叆鏂囨湰鏂囦欢
  async writeTextFile(path: string, content: string): Promise<void> {
    if (isTauriCached()) {
      const { writeFile } = await import('@tauri-apps/plugin-fs');
      const encoder = new TextEncoder();
      await writeFile(path, encoder.encode(content));
    } else {
      // 娴忚鍣ㄧ幆澧冮渶瑕佷紶鍏?handle
      throw new Error('Browser environment requires file handle');
    }
  },

  // 鍒涘缓鐩綍
  async createDir(path: string): Promise<void> {
    if (isTauriCached()) {
      const { mkdir } = await import('@tauri-apps/plugin-fs');
      await mkdir(path, { recursive: true });
    } else {
      throw new Error('Browser environment requires directory handle');
    }
  },

  // 鍒犻櫎鏂囦欢
  async removeFile(path: string): Promise<void> {
    if (isTauriCached()) {
      const { remove } = await import('@tauri-apps/plugin-fs');
      await remove(path);
    } else {
      throw new Error('Browser environment requires directory handle');
    }
  },

  // 閲嶅懡鍚嶆枃浠禱n  async renameFile(oldPath: string, newPath: string): Promise<void> {
    if (isTauriCached()) {
      const { rename } = await import('@tauri-apps/plugin-fs');
      await rename(oldPath, newPath);
    } else {
      throw new Error('Browser environment requires directory handle');
    }
  },

  // 璇诲彇鐩綍
  async readDir(
    path: string,
  ): Promise<Array<{ name: string; isFile: boolean; isDirectory: boolean }>> {
    if (isTauriCached()) {
      const { readDir } = await import('@tauri-apps/plugin-fs');
      const entries = await readDir(path);
      return entries.map((entry) => ({
        name: entry.name!,
        isFile: entry.isFile!,
        isDirectory: entry.isDirectory!,
      }));
    } else {
      throw new Error('Browser environment requires directory handle');
    }
  },

  // 妫€鏌ユ枃浠舵槸鍚﹀瓨鍦╘n  async exists(path: string): Promise<boolean> {
    if (isTauriCached()) {
      const { exists } = await import('@tauri-apps/plugin-fs');
      return await exists(path);
    } else {
      throw new Error('Browser environment requires file handle');
    }
  },
};
